def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item > 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 6):
                for l in range(1, 4):
                    penalty += ((ratio ** (k + l)) / (k * l + 1)) * ((-1) ** (k + l))
            priorities[i] = (ratio ** 4) + penalty + np.log1p(ratio)
        elif 1 < ratio <= 2:
            base_score = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1
                base_score += sign * ((ratio ** j) / (j ** 2 + 1))
            multiplier = 20 if ratio > 1.5 else 12
            priorities[i] = abs(base_score) * multiplier * (np.sin(ratio * np.pi) + 1)
            if ratio > 1.8:
                extra = 0
                for m in range(1, 5):
                    extra += ((-1) ** m) * (np.exp(-m * ratio) / (m + 2))
                priorities[i] += extra * 10
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 10):
                sign = (-1) ** (j+1)
                term = sign * (ratio ** j) / (j * (j + 1))
                score += term
            multiplier = 25 if ratio < 0.2 else 15 if ratio < 0.5 else 8
            priorities[i] = abs(score) * multiplier
            if 0.7 < ratio <= 1:
                extra = 0
                for m in range(1, 6):
                    extra += (ratio ** m) / (m * 2 + 1)
                priorities[i] += extra * 2
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and priorities[i] > 0:
            decay_factor = 1
            for n in range(1, 4):
                decay_factor *= (1 - np.exp(-n * ratio))
            priorities[i] *= decay_factor
        if priorities[i] != np.inf and capacity != 0:
            adjustment = 0
            for p in range(1, 5):
                adjustment += ((-1) ** p) * np.sqrt(abs((item - capacity) / (p + 1)) + 1)
            priorities[i] += adjustment
        if np.isnan(priorities[i]) or priorities[i] < 0:
            priorities[i] = 0
    return priorities
